      },
      "notes": "Tests the ability to retrieve similar challenges for context."
    },
    {
      "name": "edge_case_empty_input",
      "input": {
        "user_input": ""
      },
      "output": {
        "error": "User input cannot be empty."
      },
      "notes": "Edge case to ensure the system handles empty input gracefully."
    },
    {
      "name": "adversarial_case_unrelated_input",
      "input": {
        "user_input": "Tell me a joke"
      },
      "output": {
        "error": "Input must relate to a project or challenge."
